import React, { useState } from 'react';
import './Calculator.css';

function Calculator({ subject = 'maths' }) {
  const [calcType, setCalcType] = useState('basic');
  const [inputs, setInputs] = useState({});
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const API_BASE = 'http://localhost:5000/api';

  const handleInputChange = (key, value) => {
    setInputs({ ...inputs, [key]: parseFloat(value) || value });
  };

  const calculate = async (endpoint, params) => {
    try {
      setError(null);
      const response = await fetch(`${API_BASE}${endpoint}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(params)
      });
      const data = await response.json();
      
      if (data.success) {
        setResult(data);
      } else {
        setError(data.error);
      }
    } catch (err) {
      setError('Server error: ' + err.message);
    }
  };

  return (
    <div className="calculator-container">
      <h1>🧮 SSC Maths Calculator</h1>
      <p className="subtitle">Interactive calculation tools for all topics</p>

      <div className="calc-selector">
        <button 
          className={`calc-tab ${calcType === 'basic' ? 'active' : ''}`}
          onClick={() => setCalcType('basic')}
        >
          Basic Calc
        </button>
        <button 
          className={`calc-tab ${calcType === 'hcf-lcm' ? 'active' : ''}`}
          onClick={() => setCalcType('hcf-lcm')}
        >
          HCF/LCM
        </button>
        <button 
          className={`calc-tab ${calcType === 'percentage' ? 'active' : ''}`}
          onClick={() => setCalcType('percentage')}
        >
          Percentage
        </button>
        <button 
          className={`calc-tab ${calcType === 'profit-loss' ? 'active' : ''}`}
          onClick={() => setCalcType('profit-loss')}
        >
          Profit/Loss
        </button>
        <button 
          className={`calc-tab ${calcType === 'interest' ? 'active' : ''}`}
          onClick={() => setCalcType('interest')}
        >
          Interest
        </button>
        <button 
          className={`calc-tab ${calcType === 'speed' ? 'active' : ''}`}
          onClick={() => setCalcType('speed')}
        >
          Speed/Distance
        </button>
      </div>

      <div className="calc-panel">
        {/* Basic Calculator */}
        {calcType === 'basic' && (
          <div className="calc-input-group">
            <h3>Basic Arithmetic</h3>
            <div className="input-row">
              <input 
                type="number" 
                placeholder="Number 1"
                onChange={(e) => handleInputChange('num1', e.target.value)}
              />
              <select onChange={(e) => handleInputChange('operation', e.target.value)}>
                <option value="+">+</option>
                <option value="-">-</option>
                <option value="*">×</option>
                <option value="/">÷</option>
              </select>
              <input 
                type="number" 
                placeholder="Number 2"
                onChange={(e) => handleInputChange('num2', e.target.value)}
              />
            </div>
            <button className="calc-btn" onClick={() => {
              const op = inputs.operation;
              let res;
              if (op === '+') res = inputs.num1 + inputs.num2;
              else if (op === '-') res = inputs.num1 - inputs.num2;
              else if (op === '*') res = inputs.num1 * inputs.num2;
              else if (op === '/') res = inputs.num1 / inputs.num2;
              setResult({ result: res });
            }}>
              Calculate
            </button>
          </div>
        )}

        {/* HCF/LCM Calculator */}
        {calcType === 'hcf-lcm' && (
          <div className="calc-input-group">
            <h3>HCF & LCM</h3>
            <div className="input-row">
              <input 
                type="number" 
                placeholder="Number 1"
                onChange={(e) => handleInputChange('a', e.target.value)}
              />
              <input 
                type="number" 
                placeholder="Number 2"
                onChange={(e) => handleInputChange('b', e.target.value)}
              />
            </div>
            <div className="button-row">
              <button className="calc-btn" onClick={() => 
                calculate('/hcf', { a: inputs.a, b: inputs.b })
              }>
                Calculate HCF
              </button>
              <button className="calc-btn" onClick={() => 
                calculate('/lcm', { a: inputs.a, b: inputs.b })
              }>
                Calculate LCM
              </button>
            </div>
          </div>
        )}

        {/* Percentage Calculator */}
        {calcType === 'percentage' && (
          <div className="calc-input-group">
            <h3>Percentage Calculation</h3>
            <div className="input-row">
              <input 
                type="number" 
                placeholder="Value"
                onChange={(e) => handleInputChange('value', e.target.value)}
              />
              <input 
                type="number" 
                placeholder="Percentage %"
                onChange={(e) => handleInputChange('percent', e.target.value)}
              />
            </div>
            <button className="calc-btn" onClick={() => 
              calculate('/percentage', { value: inputs.value, percent: inputs.percent })
            }>
              Calculate
            </button>
          </div>
        )}

        {/* Profit/Loss Calculator */}
        {calcType === 'profit-loss' && (
          <div className="calc-input-group">
            <h3>Profit & Loss</h3>
            <div className="input-row">
              <input 
                type="number" 
                placeholder="Cost Price (CP)"
                onChange={(e) => handleInputChange('cp', e.target.value)}
              />
              <input 
                type="number" 
                placeholder="Selling Price (SP)"
                onChange={(e) => handleInputChange('sp', e.target.value)}
              />
            </div>
            <button className="calc-btn" onClick={() => 
              calculate('/profit-loss', { cp: inputs.cp, sp: inputs.sp })
            }>
              Calculate
            </button>
          </div>
        )}

        {/* Interest Calculator */}
        {calcType === 'interest' && (
          <div className="calc-input-group">
            <h3>Simple & Compound Interest</h3>
            <div className="input-row">
              <input 
                type="number" 
                placeholder="Principal"
                onChange={(e) => handleInputChange('principal', e.target.value)}
              />
              <input 
                type="number" 
                placeholder="Rate % per annum"
                onChange={(e) => handleInputChange('rate', e.target.value)}
              />
              <input 
                type="number" 
                placeholder="Time (years)"
                onChange={(e) => handleInputChange('time', e.target.value)}
              />
            </div>
            <div className="button-row">
              <button className="calc-btn" onClick={() => 
                calculate('/simple-interest', { 
                  principal: inputs.principal, 
                  rate: inputs.rate, 
                  time: inputs.time 
                })
              }>
                Simple Interest
              </button>
              <button className="calc-btn" onClick={() => 
                calculate('/compound-interest', { 
                  principal: inputs.principal, 
                  rate: inputs.rate, 
                  time: inputs.time 
                })
              }>
                Compound Interest
              </button>
            </div>
          </div>
        )}

        {/* Speed Calculator */}
        {calcType === 'speed' && (
          <div className="calc-input-group">
            <h3>Speed, Distance & Time</h3>
            <div className="input-row">
              <input 
                type="number" 
                placeholder="Speed (km/h)"
                onChange={(e) => handleInputChange('speed', e.target.value)}
              />
              <input 
                type="number" 
                placeholder="Distance (km)"
                onChange={(e) => handleInputChange('distance', e.target.value)}
              />
              <input 
                type="number" 
                placeholder="Time (hours)"
                onChange={(e) => handleInputChange('time', e.target.value)}
              />
            </div>
            <button className="calc-btn" onClick={() => 
              calculate('/speed-distance-time', { 
                speed: inputs.speed, 
                distance: inputs.distance, 
                time: inputs.time 
              })
            }>
              Calculate Missing Value
            </button>
          </div>
        )}

        {error && <div className="error-message">{error}</div>}

        {result && (
          <div className="result-box">
            <h4>📊 Result</h4>
            <div className="result-content">
              {typeof result === 'object' && (
                Object.entries(result).map(([key, value]) => (
                  <div key={key} className="result-item">
                    <strong>{key.replace(/_/g, ' ').toUpperCase()}:</strong>
                    <span className="result-value">
                      {typeof value === 'number' ? value.toFixed(2) : JSON.stringify(value)}
                    </span>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Calculator;
